tooltip.css:
.tooltip_SVGID_ { max-width: 260px;
          white-space: normal;
          background-color: rgba(0,0,0,0.88);
          color: #fff;
          padding: 6px 10px;
          border-radius: 6px;
          border: 0;
          box-shadow: 0 2px 6px rgba(0,0,0,0.25); ; position:absolute;pointer-events:none;z-index:999;}

